INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u06-l1','B2','reading','b2-u06','normal',1,'Causative Have & Get','have/get + something + done — nhờ người khác làm',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u06-l1-p1','b2-u06-l1','multiple_choice',1,'practice','easy',false,'{"question":"''Tôi nhờ người sửa máy tính.'' — Câu nào ĐÚNG?","options":[{"id":"a","text":"I repaired my computer."},{"id":"b","text":"I had my computer repaired."},{"id":"c","text":"I had repaired my computer."}],"correctOptionId":"b","explanationVi":"Nhờ người khác làm: have + object + V3."}'::jsonb),
 ('b2-u06-l1-p2','b2-u06-l1','grammar_fill_blank',2,'practice','easy',false,'{"question":"Chia động từ: ''She ___ her nails ___ (do) before the party.''","acceptedAnswers":["got / done","had / done"],"explanationVi":"Causative: got/had + object + V3."}'::jsonb),
 ('b2-u06-l1-p3','b2-u06-l1','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"renovate","right":"cải tạo, tu sửa"},{"left":"install","right":"lắp đặt"},{"left":"tailor-made","right":"may riêng"},{"left":"get something done","right":"nhờ làm (thông thường)"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u06-l1-p4','b2-u06-l1','grammar_fill_blank',4,'practice','medium',false,'{"question":"Hoàn thành: ''They ___ solar panels ___ (install) on their roof last summer.''","acceptedAnswers":["had / installed","got / installed"],"explanationVi":"have/get + object + V3."}'::jsonb),
 ('b2-u06-l1-p5','b2-u06-l1','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Chúng tôi đang nhờ người cải tạo nhà lúc này.","acceptedAnswers":["We are having our house renovated at the moment.","We''re having the house renovated at the moment.","We are getting the house renovated at the moment."],"explanationVi":"Progressive causative: be having/getting something done."}'::jsonb),
 ('b2-u06-l1-p6','b2-u06-l1','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi: ''I got my brother fix the car.''","acceptedAnswers":["I got my brother to fix the car."],"explanationVi":"get + person + TO DO (infinitive)."}'::jsonb),
 ('b2-u06-l1-p7','b2-u06-l1','multiple_choice',7,'practice','medium',false,'{"question":"Phân biệt: ''I cut my hair'' vs ''I had my hair cut'' — câu nào nghĩa là nhờ thợ?","options":[{"id":"a","text":"I cut my hair."},{"id":"b","text":"I had my hair cut."},{"id":"c","text":"Cả hai đều như nhau."}],"correctOptionId":"b","explanationVi":"have + hair + cut = nhờ thợ cắt; I cut = tự cắt."}'::jsonb),
 ('b2-u06-l1-q1','b2-u06-l1','multiple_choice',8,'quiz','easy',true,'{"question":"Cấu trúc causative đúng là?","options":[{"id":"a","text":"have + V3 + object"},{"id":"b","text":"have + object + V3"},{"id":"c","text":"have + object + to V"}],"correctOptionId":"b","explanationVi":"Causative: have + object + V3."}'::jsonb),
 ('b2-u06-l1-q2','b2-u06-l1','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Chia động từ: ''I''m going to have my teeth ___ (check) next week.''","acceptedAnswers":["checked"],"explanationVi":"have + teeth + checked."}'::jsonb),
 ('b2-u06-l1-q3','b2-u06-l1','multiple_choice',10,'quiz','medium',true,'{"question":"Chọn câu ĐÚNG nghĩa ''nhờ thợ sơn nhà'':","options":[{"id":"a","text":"I painted the house."},{"id":"b","text":"I had the house painted."},{"id":"c","text":"I had painted the house."}],"correctOptionId":"b","explanationVi":"had + house + painted = nhờ thợ sơn."}'::jsonb),
 ('b2-u06-l1-q4','b2-u06-l1','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Chia động từ: ''She ___ her dress ___ (design) especially for the event.''","acceptedAnswers":["had / designed","got / designed"],"explanationVi":"have/get + dress + designed."}'::jsonb),
 ('b2-u06-l1-q5','b2-u06-l1','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"renovate","right":"cải tạo"},{"left":"install","right":"lắp đặt"},{"left":"tailor-made","right":"may riêng"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u06-l1-q6','b2-u06-l1','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["installed","We","solar","panels","had","our","roof","on"],"correctOrder":[1,4,2,3,0,5,6,7],"explanationVi":"We had solar panels installed on our roof."}'::jsonb),
 ('b2-u06-l1-q7','b2-u06-l1','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chia động từ: ''He got his assistant ___ (book) the flights.''","acceptedAnswers":["to book"],"explanationVi":"get + person + to do."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u06-l2','B2','reading','b2-u06','normal',2,'Reported Speech: Orders & Requests','tell/ask/order/warn + object + to-infinitive',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u06-l2-p1','b2-u06-l2','multiple_choice',1,'practice','easy',false,'{"question":"''Don''t open the door.'' → She warned me ___ the door.","options":[{"id":"a","text":"not to open"},{"id":"b","text":"don''t open"},{"id":"c","text":"to not opening"}],"correctOptionId":"a","explanationVi":"Phủ định reported: warn + object + not to do."}'::jsonb),
 ('b2-u06-l2-p2','b2-u06-l2','grammar_fill_blank',2,'practice','easy',false,'{"question":"Chuyển sang gián tiếp: ''Submit the report by Friday!'' → The manager told me ___ the report by Friday.","acceptedAnswers":["to submit"],"explanationVi":"tell + object + to do."}'::jsonb),
 ('b2-u06-l2-p3','b2-u06-l2','vocabulary_match',3,'practice','easy',false,'{"question":"Nối động từ với nghĩa:","pairs":[{"left":"order","right":"ra lệnh"},{"left":"warn","right":"cảnh báo"},{"left":"forbid","right":"cấm"},{"left":"encourage","right":"khuyến khích"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u06-l2-p4','b2-u06-l2','grammar_fill_blank',4,'practice','medium',false,'{"question":"Chuyển sang gián tiếp: ''You should apply for the scholarship.'' → She advised him ___ for the scholarship.","acceptedAnswers":["to apply"],"explanationVi":"advise + object + to do."}'::jsonb),
 ('b2-u06-l2-p5','b2-u06-l2','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Anh ấy nhắc tôi nhớ mang theo hộ chiếu.","acceptedAnswers":["He reminded me to bring my passport.","He reminded me to take my passport."],"explanationVi":"remind + object + to do."}'::jsonb),
 ('b2-u06-l2-p6','b2-u06-l2','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi: ''He said me to leave immediately.''","acceptedAnswers":["He told me to leave immediately."],"explanationVi":"say không có object + to; dùng tell + object + to do."}'::jsonb),
 ('b2-u06-l2-p7','b2-u06-l2','multiple_choice',7,'practice','medium',false,'{"question":"''Stop talking in class!'' → The teacher ___ them ___ in class.","options":[{"id":"a","text":"told / to stop talking"},{"id":"b","text":"said / stop talking"},{"id":"c","text":"ordered / not stop talking"}],"correctOptionId":"a","explanationVi":"told + object + to stop talking."}'::jsonb),
 ('b2-u06-l2-q1','b2-u06-l2','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG (reported request):","options":[{"id":"a","text":"She asked me helping her."},{"id":"b","text":"She asked me to help her."},{"id":"c","text":"She asked that I help her."}],"correctOptionId":"b","explanationVi":"ask + object + to do."}'::jsonb),
 ('b2-u06-l2-q2','b2-u06-l2','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Chuyển sang gián tiếp: ''Don''t worry!'' → She told me ___ worry.","acceptedAnswers":["not to"],"explanationVi":"tell + object + not to do."}'::jsonb),
 ('b2-u06-l2-q3','b2-u06-l2','multiple_choice',10,'quiz','medium',true,'{"question":"Động từ nào cần object trực tiếp trước to-infinitive?","options":[{"id":"a","text":"say"},{"id":"b","text":"tell"},{"id":"c","text":"suggest"}],"correctOptionId":"b","explanationVi":"tell + object + to do; say không có object trực tiếp."}'::jsonb),
 ('b2-u06-l2-q4','b2-u06-l2','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Chuyển sang gián tiếp: ''You must not enter this area!'' → The officer forbade them ___ that area.","acceptedAnswers":["to enter"],"explanationVi":"forbid + object + to do."}'::jsonb),
 ('b2-u06-l2-q5','b2-u06-l2','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối động từ với nghĩa:","pairs":[{"left":"remind","right":"nhắc nhở"},{"left":"encourage","right":"khuyến khích"},{"left":"warn","right":"cảnh báo"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u06-l2-q6','b2-u06-l2','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["late","told","not","She","be","me","to"],"correctOrder":[3,1,2,4,5,0,6],"explanationVi":"She told me not to be late."}'::jsonb),
 ('b2-u06-l2-q7','b2-u06-l2','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chuyển sang gián tiếp: ''Work harder!'' → The coach encouraged them ___ harder.","acceptedAnswers":["to work"],"explanationVi":"encourage + object + to do."}'::jsonb);
