 ('b2-u06-l3-p2','b2-u06-l3','vocabulary_match',2,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"refurbish","right":"tân trang lại"},{"left":"alter","right":"chỉnh sửa"},{"left":"dry-clean","right":"giặt khô"},{"left":"upkeep","right":"chi phí bảo dưỡng"}],"explanationVi":"Ghép đúng."}'::jsonb),
