 ('b2-u06-l3-p6','b2-u06-l3','multiple_choice',6,'practice','medium',false,'{"question":"Từ nào mô tả dịch vụ được thực hiện ngay tại địa điểm?","options":[{"id":"a","text":"on-site"},{"id":"b","text":"tailor-made"},{"id":"c","text":"upkeep"}],"correctOptionId":"a","explanationVi":"on-site = tại chỗ."}'::jsonb),
 ('b2-u06-l3-p7','b2-u06-l3','vocabulary_match',7,'practice','easy',false,'{"question":"Nối từ còn lại:","pairs":[{"left":"premises","right":"cơ sở, địa điểm"},{"left":"on-site","right":"tại chỗ"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u06-l3-q1','b2-u06-l3','vocabulary_match',8,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"electrician","right":"thợ điện"},{"left":"refurbish","right":"tân trang"},{"left":"maintenance","right":"bảo trì"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u06-l3-q2','b2-u06-l3','multiple_choice',9,'quiz','easy',true,'{"question":"Từ nào chỉ người sửa đường ống nước?","options":[{"id":"a","text":"contractor"},{"id":"b","text":"plumber"},{"id":"c","text":"electrician"}],"correctOptionId":"b","explanationVi":"plumber = thợ sửa ống nước."}'::jsonb),
 ('b2-u06-l3-q3','b2-u06-l3','multiple_choice',10,'quiz','medium',true,'{"question":"Điền từ đúng: ''I had my coat ___ — it''s much cleaner now.''","options":[{"id":"a","text":"altered"},{"id":"b","text":"dry-cleaned"},{"id":"c","text":"refurbished"}],"correctOptionId":"b","explanationVi":"have + coat + dry-cleaned."}'::jsonb),
 ('b2-u06-l3-q4','b2-u06-l3','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền từ đúng: ''The company has had its ___ completely renovated.''","acceptedAnswers":["premises"],"explanationVi":"premises = cơ sở (business location)."}'::jsonb),
 ('b2-u06-l3-q5','b2-u06-l3','multiple_choice',12,'quiz','medium',true,'{"question":"Điền từ đúng: ''We need to get the wiring checked by a qualified ___.''","options":[{"id":"a","text":"contractor"},{"id":"b","text":"plumber"},{"id":"c","text":"electrician"}],"correctOptionId":"c","explanationVi":"electrician = thợ điện."}'::jsonb),
 ('b2-u06-l3-q6','b2-u06-l3','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["suit","had","his","He","altered","tailor-made","a"],"correctOrder":[3,1,2,0,4,5,6],"explanationVi":"He had his suit altered — or He had a tailor-made suit."}'::jsonb),
 ('b2-u06-l3-q7','b2-u06-l3','vocabulary_match',14,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"upkeep","right":"chi phí bảo dưỡng"},{"left":"on-site","right":"tại chỗ"},{"left":"alter","right":"chỉnh sửa"}],"explanationVi":"Ghép đúng."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u06-l4','B2','reading','b2-u06','normal',4,'Home Renovation Project','Đọc hiểu: Dự án cải tạo nhà',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u06-l4-p1','b2-u06-l4','multiple_choice',1,'practice','easy',false,'{"question":"Minh và Lan dự kiến dự án mất bao lâu?","options":[{"id":"a","text":"Ba tuần"},{"id":"b","text":"Sáu tuần"},{"id":"c","text":"Hai tháng"}],"correctOptionId":"b","explanationVi":"''expected it to take six weeks.''"}'::jsonb),
 ('b2-u06-l4-p2','b2-u06-l4','multiple_choice',2,'practice','easy',false,'{"question":"Họ nhờ làm những gì trong căn hộ? (chọn sai)","options":[{"id":"a","text":"Trát lại tường và lát lại sàn"},{"id":"b","text":"Tân trang nhà bếp"},{"id":"c","text":"Xây thêm phòng ngủ"}],"correctOptionId":"c","explanationVi":"Bài không đề cập xây thêm phòng."}'::jsonb),
 ('b2-u06-l4-p3','b2-u06-l4','multiple_choice',3,'practice','medium',false,'{"question":"Vấn đề chính xảy ra với dự án là gì?","options":[{"id":"a","text":"Nhà thầu bỏ việc"},{"id":"b","text":"Dự án bị chậm và thợ điện chưa được gọi"},{"id":"c","text":"Họ không có ngân sách"}],"correctOptionId":"b","explanationVi":"''the project overran'' + ''electrician still hadn''t been called.''"}'::jsonb),
 ('b2-u06-l4-p4','b2-u06-l4','vocabulary_match',4,'practice','easy',false,'{"question":"Nối từ trong bài với nghĩa:","pairs":[{"left":"quote","right":"báo giá"},{"left":"overrun","right":"vượt mức"},{"left":"disruption","right":"sự gián đoạn"},{"left":"deadline","right":"hạn chót"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u06-l4-p5','b2-u06-l4','multiple_choice',5,'practice','medium',false,'{"question":"Lan khuyên Minh điều gì cho lần sau?","options":[{"id":"a","text":"Chọn nhà thầu khác"},{"id":"b","text":"Lấy mọi thứ bằng văn bản"},{"id":"c","text":"Tự làm không thuê thầu"}],"correctOptionId":"b","explanationVi":"''advised him to get everything in writing next time.''"}'::jsonb),
 ('b2-u06-l4-p6','b2-u06-l4','multiple_choice',6,'practice','medium',false,'{"question":"Cấu trúc nào xuất hiện trong: ''They''re now having new furniture delivered''?","options":[{"id":"a","text":"Reported speech"},{"id":"b","text":"Passive reporting"},{"id":"c","text":"Progressive causative"}],"correctOptionId":"c","explanationVi":"be having something delivered = causative progressive."}'::jsonb),
 ('b2-u06-l4-p7','b2-u06-l4','grammar_fill_blank',7,'practice','medium',false,'{"question":"Hoàn thành câu tiếc nuối trong bài: ''We should ___ the contract checked by a lawyer.''","acceptedAnswers":["have had"],"explanationVi":"should have had + object + V3 = tiếc nuối causative."}'::jsonb),
 ('b2-u06-l4-q1','b2-u06-l4','multiple_choice',8,'quiz','easy',true,'{"question":"Cuối cùng họ có hài lòng với kết quả không?","options":[{"id":"a","text":"Không, quá thất vọng"},{"id":"b","text":"Có, đúng như hình dung"},{"id":"c","text":"Chỉ hài lòng một phần"}],"correctOptionId":"b","explanationVi":"''the finished apartment was exactly what they had imagined.''"}'::jsonb),
 ('b2-u06-l4-q2','b2-u06-l4','multiple_choice',9,'quiz','easy',true,'{"question":"Ai nhắc nhà thầu thu xếp công việc điện?","options":[{"id":"a","text":"Lan"},{"id":"b","text":"Minh"},{"id":"c","text":"Thợ điện"}],"correctOptionId":"b","explanationVi":"''Minh reminded the contractor to arrange the electrical work.''"}'::jsonb),
 ('b2-u06-l4-q3','b2-u06-l4','multiple_choice',10,'quiz','medium',true,'{"question":"Cấu trúc trong ''got a local contractor to provide a quote'' là?","options":[{"id":"a","text":"have + object + V3"},{"id":"b","text":"get + person + to do"},{"id":"c","text":"reported speech"}],"correctOptionId":"b","explanationVi":"get + person + to do = nhờ/thuê người cụ thể."}'::jsonb),
 ('b2-u06-l4-q4','b2-u06-l4','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Hoàn thành: ''They had the walls ___ (replaster).''","acceptedAnswers":["replastered"],"explanationVi":"have + walls + replastered."}'::jsonb),
 ('b2-u06-l4-q5','b2-u06-l4','multiple_choice',12,'quiz','medium',true,'{"question":"Từ ''overrun'' trong bài có nghĩa là?","options":[{"id":"a","text":"Hoàn thành sớm"},{"id":"b","text":"Vượt thời gian/chi phí dự kiến"},{"id":"c","text":"Huỷ bỏ"}],"correctOptionId":"b","explanationVi":"overrun = vượt mức kế hoạch."}'::jsonb),
 ('b2-u06-l4-q6','b2-u06-l4','vocabulary_match',13,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"disruption","right":"sự gián đoạn"},{"left":"quote","right":"báo giá"},{"left":"deadline","right":"hạn chót"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u06-l4-q7','b2-u06-l4','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chuyển sang gián tiếp: ''We''ll be done by Friday!'' → The contractor told them they ___ done by Friday.","acceptedAnswers":["would be"],"explanationVi":"Tường thuật: will → would."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u06-l5','B2','reading','b2-u06','unit_review',5,'Unit 6 Review','Ôn tập Unit 6: Nhờ người làm',15,35,75,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u06-l5-q1','b2-u06-l5','grammar_fill_blank',1,'quiz','easy',true,'{"question":"Chia động từ: ''I need to have my passport ___ (renew).''","acceptedAnswers":["renewed"],"explanationVi":"have + passport + renewed."}'::jsonb),
 ('b2-u06-l5-q2','b2-u06-l5','multiple_choice',2,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG (nhờ thợ sơn nhà):","options":[{"id":"a","text":"I painted the house last week."},{"id":"b","text":"I had the house painted last week."},{"id":"c","text":"I had painted the house last week."}],"correctOptionId":"b","explanationVi":"Causative: had + house + painted."}'::jsonb),
 ('b2-u06-l5-q3','b2-u06-l5','multiple_choice',3,'quiz','easy',true,'{"question":"Chuyển sang gián tiếp: ''Please help me.'' → She asked me ___ her.","options":[{"id":"a","text":"help"},{"id":"b","text":"to help"},{"id":"c","text":"helping"}],"correctOptionId":"b","explanationVi":"ask + object + to do."}'::jsonb),
 ('b2-u06-l5-q4','b2-u06-l5','grammar_fill_blank',4,'quiz','medium',true,'{"question":"Chia động từ: ''They are having the office ___ (refurbish) at the moment.''","acceptedAnswers":["refurbished"],"explanationVi":"Progressive causative: are having + office + refurbished."}'::jsonb),
 ('b2-u06-l5-q5','b2-u06-l5','multiple_choice',5,'quiz','medium',true,'{"question":"Câu nào ĐÚNG (get + person + to do):","options":[{"id":"a","text":"I got my assistant fixed the problem."},{"id":"b","text":"I got my assistant to fix the problem."},{"id":"c","text":"I got my assistant fixing the problem."}],"correctOptionId":"b","explanationVi":"get + person + to do (infinitive)."}'::jsonb),
 ('b2-u06-l5-q6','b2-u06-l5','vocabulary_match',6,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"contractor","right":"nhà thầu"},{"left":"plumber","right":"thợ ống nước"},{"left":"maintenance","right":"bảo trì"},{"left":"refurbish","right":"tân trang"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u06-l5-q7','b2-u06-l5','grammar_fill_blank',7,'quiz','medium',true,'{"question":"Chuyển sang gián tiếp: ''Don''t touch the equipment!'' → The supervisor warned them ___ the equipment.","acceptedAnswers":["not to touch"],"explanationVi":"warn + object + not to do."}'::jsonb),
 ('b2-u06-l5-q8','b2-u06-l5','sentence_ordering',8,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["checked","the","have","should","contract","We","by","a","have","lawyer"],"correctOrder":[5,8,1,4,3,2,6,7,0,9],"explanationVi":"We should have had the contract checked by a lawyer."}'::jsonb),
 ('b2-u06-l5-q9','b2-u06-l5','multiple_choice',9,'quiz','medium',true,'{"question":"Động từ nào KHÔNG dùng theo mẫu tell/ask + object + to do?","options":[{"id":"a","text":"order"},{"id":"b","text":"say"},{"id":"c","text":"remind"}],"correctOptionId":"b","explanationVi":"say không có object trực tiếp trước to-infinitive."}'::jsonb),
 ('b2-u06-l5-q10','b2-u06-l5','grammar_fill_blank',10,'quiz','hard',true,'{"question":"Chia động từ: ''They got a specialist ___ (assess) the damage.''","acceptedAnswers":["to assess"],"explanationVi":"get + person + to do."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u07-l1','B2','reading','b2-u07','normal',1,'Deduction About the Past','must/can''t/could/might + have + V3 — suy luận quá khứ',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u07-l1-p1','b2-u07-l1','multiple_choice',1,'practice','easy',false,'{"question":"''The lights are on but nobody answers.'' → She ___ home.","options":[{"id":"a","text":"must be"},{"id":"b","text":"must have gone"},{"id":"c","text":"can''t have been"}],"correctOptionId":"b","explanationVi":"Đèn sáng → gần chắc đã về: must have gone."}'::jsonb),
 ('b2-u07-l1-p2','b2-u07-l1','grammar_fill_blank',2,'practice','easy',false,'{"question":"Điền modal đúng: ''He ___ (eat) the cake — he''s allergic to eggs.''","acceptedAnswers":["can''t have eaten","couldn''t have eaten"],"explanationVi":"Không thể đã ăn vì dị ứng → can''t have eaten."}'::jsonb),
 ('b2-u07-l1-p3','b2-u07-l1','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"deduce","right":"suy luận"},{"left":"clue","right":"manh mối"},{"left":"suspect","right":"nghi phạm"},{"left":"alibi","right":"bằng chứng ngoại phạm"}],"explanationVi":"Từ vựng điều tra."}'::jsonb),
 ('b2-u07-l1-p4','b2-u07-l1','grammar_fill_blank',4,'practice','medium',false,'{"question":"Điền modal đúng (yếu, không chắc): ''She ___ (take) the wrong bus — she''s 30 minutes late.''","acceptedAnswers":["might have taken","could have taken","may have taken"],"explanationVi":"Không chắc → might/could/may have taken."}'::jsonb),
 ('b2-u07-l1-p5','b2-u07-l1','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Nghi phạm chắc hẳn đã biết về kế hoạch — anh ta có mặt tại cuộc họp.","acceptedAnswers":["The suspect must have known about the plan — he was at the meeting.","The suspect must have known the plan — he was present at the meeting."],"explanationVi":"Gần chắc đã biết: must have known."}'::jsonb),
 ('b2-u07-l1-p6','b2-u07-l1','multiple_choice',6,'practice','medium',false,'{"question":"''There are muddy footprints on the floor.'' → Someone ___ through the garden.","options":[{"id":"a","text":"must have walked"},{"id":"b","text":"must walk"},{"id":"c","text":"could walk"}],"correctOptionId":"a","explanationVi":"Bằng chứng rõ ràng → must have walked."}'::jsonb),
 ('b2-u07-l1-p7','b2-u07-l1','error_correction',7,'practice','medium',false,'{"question":"Sửa lỗi: ''She must left her keys inside.''","acceptedAnswers":["She must have left her keys inside."],"explanationVi":"Suy luận quá khứ: must have + V3."}'::jsonb),
 ('b2-u07-l1-q1','b2-u07-l1','multiple_choice',8,'quiz','easy',true,'{"question":"Modal nào diễn đạt ''gần như chắc chắn không xảy ra''?","options":[{"id":"a","text":"must have"},{"id":"b","text":"might have"},{"id":"c","text":"can''t have"}],"correctOptionId":"c","explanationVi":"can''t have = gần như chắc chắn không."}'::jsonb),
 ('b2-u07-l1-q2','b2-u07-l1','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền đúng: ''The door is locked — they ___ (leave) already.''","acceptedAnswers":["must have left"],"explanationVi":"Cửa khoá → gần chắc đã đi: must have left."}'::jsonb),
 ('b2-u07-l1-q3','b2-u07-l1','multiple_choice',10,'quiz','medium',true,'{"question":"''She has a perfect alibi — she was in hospital.'' → She ___ the crime.","options":[{"id":"a","text":"must have committed"},{"id":"b","text":"might have committed"},{"id":"c","text":"can''t have committed"}],"correctOptionId":"c","explanationVi":"Có alibi → không thể đã làm: can''t have committed."}'::jsonb),
 ('b2-u07-l1-q4','b2-u07-l1','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền đúng (khả năng yếu): ''He ___ (forget) the password — he always forgets things.''","acceptedAnswers":["might have forgotten","could have forgotten","may have forgotten"],"explanationVi":"Khả năng có thể → might/could/may have forgotten."}'::jsonb),
 ('b2-u07-l1-q5','b2-u07-l1','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"evidence","right":"bằng chứng"},{"left":"deduce","right":"suy luận"},{"left":"clue","right":"manh mối"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u07-l1-q6','b2-u07-l1','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["must","She","the","have","early","meeting","left","before"],"correctOrder":[1,0,3,4,2,5,6,7],"explanationVi":"She must have left before the early meeting."}'::jsonb),
 ('b2-u07-l1-q7','b2-u07-l1','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Điền đúng: ''The wallet is gone — someone ___ (steal) it while we were distracted.''","acceptedAnswers":["must have stolen","could have stolen","might have stolen"],"explanationVi":"Ví đã mất → suy luận đã bị lấy."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u07-l2','B2','reading','b2-u07','normal',2,'Criticism & Regret','should/ought to + have + V3 — phê bình & tiếc nuối',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u07-l2-p1','b2-u07-l2','multiple_choice',1,'practice','easy',false,'{"question":"Chọn câu ĐÚNG: ''Lẽ ra anh ấy không nên nói điều đó.''","options":[{"id":"a","text":"He should have said that."},{"id":"b","text":"He shouldn''t have said that."},{"id":"c","text":"He needn''t have said that."}],"correctOptionId":"b","explanationVi":"Phê bình đã làm điều không nên: shouldn''t have said."}'::jsonb),
 ('b2-u07-l2-p2','b2-u07-l2','grammar_fill_blank',2,'practice','easy',false,'{"question":"Điền đúng: ''You ___ (call) an ambulance immediately.''","acceptedAnswers":["should have called","ought to have called"],"explanationVi":"Lẽ ra nên gọi (nhưng không gọi): should have called."}'::jsonb),
 ('b2-u07-l2-p3','b2-u07-l2','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"in hindsight","right":"nhìn lại"},{"left":"oversight","right":"sự bỏ sót"},{"left":"negligent","right":"cẩu thả"},{"left":"precaution","right":"biện pháp phòng ngừa"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u07-l2-p4','b2-u07-l2','grammar_fill_blank',4,'practice','medium',false,'{"question":"Điền đúng: ''You ___ (bring) an umbrella — it wasn''t necessary, the sun shone all day.''","acceptedAnswers":["needn''t have brought"],"explanationVi":"Đã mang nhưng không cần: needn''t have brought."}'::jsonb),
 ('b2-u07-l2-p5','b2-u07-l2','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Nhìn lại, lẽ ra chúng tôi nên đặt vé máy bay sớm hơn.","acceptedAnswers":["In hindsight, we should have booked the flights earlier.","Looking back, we ought to have booked the tickets earlier."],"explanationVi":"In hindsight + should have booked."}'::jsonb),
 ('b2-u07-l2-p6','b2-u07-l2','multiple_choice',6,'practice','medium',false,'{"question":"Phân biệt: ''I needn''t have paid'' vs ''I didn''t need to pay'' — câu nào nghĩa là KHÔNG trả tiền?","options":[{"id":"a","text":"I needn''t have paid."},{"id":"b","text":"I didn''t need to pay."},{"id":"c","text":"Cả hai giống nhau."}],"correctOptionId":"b","explanationVi":"didn''t need to pay = biết không cần → không trả. needn''t have paid = đã trả nhưng không cần."}'::jsonb),
 ('b2-u07-l2-p7','b2-u07-l2','error_correction',7,'practice','medium',false,'{"question":"Sửa lỗi: ''She ought have told the truth.''","acceptedAnswers":["She ought to have told the truth."],"explanationVi":"ought TO have + V3 (không bỏ to)."}'::jsonb),
 ('b2-u07-l2-q1','b2-u07-l2','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG: phê bình người đã làm điều không nên:","options":[{"id":"a","text":"You should have done that."},{"id":"b","text":"You shouldn''t have done that."},{"id":"c","text":"You needn''t have done that."}],"correctOptionId":"b","explanationVi":"Phê bình đã làm: shouldn''t have done."}'::jsonb),
 ('b2-u07-l2-q2','b2-u07-l2','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền đúng: ''They ___ (read) the safety instructions before operating the machine.''","acceptedAnswers":["should have read","ought to have read"],"explanationVi":"Lẽ ra nên đọc: should/ought to have read."}'::jsonb),
 ('b2-u07-l2-q3','b2-u07-l2','multiple_choice',10,'quiz','medium',true,'{"question":"Câu nào diễn đạt ''đã làm nhưng không cần thiết''?","options":[{"id":"a","text":"I should have prepared."},{"id":"b","text":"I needn''t have prepared."},{"id":"c","text":"I didn''t need to prepare."}],"correctOptionId":"b","explanationVi":"needn''t have prepared = đã chuẩn bị nhưng không cần."}'::jsonb),
 ('b2-u07-l2-q4','b2-u07-l2','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền đúng (phê bình): ''He ___ (take) more precautions — the accident could have been avoided.''","acceptedAnswers":["should have taken","ought to have taken"],"explanationVi":"Lẽ ra nên cẩn thận hơn."}'::jsonb),
 ('b2-u07-l2-q5','b2-u07-l2','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"negligent","right":"cẩu thả"},{"left":"precaution","right":"biện pháp phòng ngừa"},{"left":"oversight","right":"sự bỏ sót"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u07-l2-q6','b2-u07-l2','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["have","You","told","me","earlier","should"],"correctOrder":[1,5,0,2,3,4],"explanationVi":"You should have told me earlier."}'::jsonb),
 ('b2-u07-l2-q7','b2-u07-l2','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Phân biệt: ''She ___ (rush) — the meeting was cancelled.'' (biết trước, không vội)","acceptedAnswers":["didn''t need to rush"],"explanationVi":"Biết không cần thiết → didn''t need to rush (không vội)."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u07-l3','B2','reading','b2-u07','normal',3,'Crime & Investigation Vocabulary','Từ vựng tội phạm & điều tra B2',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u07-l3-p1','b2-u07-l3','vocabulary_match',1,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"detective","right":"thám tử"},{"left":"motive","right":"động cơ"},{"left":"testimony","right":"lời khai"},{"left":"witness","right":"nhân chứng"}],"explanationVi":"Từ vựng tội phạm."}'::jsonb),
 ('b2-u07-l3-p2','b2-u07-l3','vocabulary_match',2,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"charge","right":"buộc tội"},{"left":"acquit","right":"tuyên trắng án"},{"left":"convict","right":"kết tội"},{"left":"frame","right":"vu oan"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u07-l3-p3','b2-u07-l3','multiple_choice',3,'practice','easy',false,'{"question":"Điền từ đúng: ''The police sealed the ___ of the crime.''","options":[{"id":"a","text":"scene"},{"id":"b","text":"forensic"},{"id":"c","text":"motive"}],"correctOptionId":"a","explanationVi":"scene of the crime = hiện trường."}'::jsonb),
 ('b2-u07-l3-p4','b2-u07-l3','multiple_choice',4,'practice','medium',false,'{"question":"Phân biệt: bị ''charged'' vs bị ''convicted'' — đâu là đã kết tội?","options":[{"id":"a","text":"charged"},{"id":"b","text":"convicted"},{"id":"c","text":"Cả hai giống nhau"}],"correctOptionId":"b","explanationVi":"convicted = đã bị tòa kết tội. charged = mới bị cáo buộc."}'::jsonb),
 ('b2-u07-l3-p5','b2-u07-l3','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Cô ấy bị kết tội dựa trên bằng chứng pháp y.","acceptedAnswers":["She was convicted based on forensic evidence.","She was convicted on the basis of forensic evidence."],"explanationVi":"convicted based on forensic evidence."}'::jsonb),
 ('b2-u07-l3-p6','b2-u07-l3','multiple_choice',6,'practice','medium',false,'{"question":"Điền từ đúng: ''The detective established a clear ___ for the crime.''","options":[{"id":"a","text":"alibi"},{"id":"b","text":"motive"},{"id":"c","text":"testimony"}],"correctOptionId":"b","explanationVi":"motive = động cơ."}'::jsonb),
 ('b2-u07-l3-p7','b2-u07-l3','vocabulary_match',7,'practice','easy',false,'{"question":"Nối từ còn lại:","pairs":[{"left":"forensic","right":"pháp y"},{"left":"scene of the crime","right":"hiện trường vụ án"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u07-l3-q1','b2-u07-l3','vocabulary_match',8,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"motive","right":"động cơ"},{"left":"acquit","right":"tuyên trắng án"},{"left":"frame","right":"vu oan"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u07-l3-q2','b2-u07-l3','multiple_choice',9,'quiz','easy',true,'{"question":"Từ nào có nghĩa là ''nhân chứng''?","options":[{"id":"a","text":"suspect"},{"id":"b","text":"witness"},{"id":"c","text":"detective"}],"correctOptionId":"b","explanationVi":"witness = nhân chứng."}'::jsonb),
 ('b2-u07-l3-q3','b2-u07-l3','multiple_choice',10,'quiz','medium',true,'{"question":"Điền từ đúng: ''He was ___ with three counts of fraud.''","options":[{"id":"a","text":"convicted"},{"id":"b","text":"charged"},{"id":"c","text":"acquitted"}],"correctOptionId":"b","explanationVi":"charged with = bị cáo buộc (chưa kết tội)."}'::jsonb),
 ('b2-u07-l3-q4','b2-u07-l3','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền từ đúng: ''___ evidence showed that the crime occurred at midnight.''","acceptedAnswers":["Forensic"],"explanationVi":"Forensic evidence = bằng chứng pháp y."}'::jsonb),
 ('b2-u07-l3-q5','b2-u07-l3','multiple_choice',12,'quiz','medium',true,'{"question":"''The jury found her not guilty.'' = The jury ___ her.","options":[{"id":"a","text":"convicted"},{"id":"b","text":"acquitted"},{"id":"c","text":"charged"}],"correctOptionId":"b","explanationVi":"not guilty → acquitted = tuyên trắng án."}'::jsonb),
 ('b2-u07-l3-q6','b2-u07-l3','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["evidence","convicted","forensic","He","was","on","based"],"correctOrder":[3,1,4,5,2,0,6],"explanationVi":"He was convicted based on forensic evidence."}'::jsonb),
 ('b2-u07-l3-q7','b2-u07-l3','vocabulary_match',14,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"testimony","right":"lời khai"},{"left":"detective","right":"thám tử"},{"left":"scene of the crime","right":"hiện trường"}],"explanationVi":"Ghép đúng."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u07-l4','B2','reading','b2-u07','normal',4,'The Missing Painting','Đọc hiểu: Vụ mất tranh',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u07-l4-p1','b2-u07-l4','multiple_choice',1,'practice','easy',false,'{"question":"Theo bài, tranh bị lấy khi nào?","options":[{"id":"a","text":"Khi bảo tàng đông khách"},{"id":"b","text":"Giữa nửa đêm và 6 giờ sáng"},{"id":"c","text":"Trong giờ mở cửa"}],"correctOptionId":"b","explanationVi":"''between midnight and 6am, when the museum was closed.''"}'::jsonb),
 ('b2-u07-l4-p2','b2-u07-l4','multiple_choice',2,'practice','easy',false,'{"question":"Tại sao chuông không reo? Suy luận trong bài là?","options":[{"id":"a","text":"Chuông bị hỏng từ trước"},{"id":"b","text":"Tên trộm biết mã hoặc ai đó giả mạo hệ thống"},{"id":"c","text":"Bảo vệ tắt chuông"}],"correctOptionId":"b","explanationVi":"''must have known the security code — or might have tampered with the system.''"}'::jsonb),
 ('b2-u07-l4-p3','b2-u07-l4','multiple_choice',3,'practice','medium',false,'{"question":"Bảo vệ bị phê bình vì điều gì?","options":[{"id":"a","text":"Không kiểm tra camera mỗi giờ"},{"id":"b","text":"Không gọi cảnh sát"},{"id":"c","text":"Rời bảo tàng trước giờ"}],"correctOptionId":"a","explanationVi":"''should have checked the cameras every hour, but...was absent.''"}'::jsonb),
 ('b2-u07-l4-p4','b2-u07-l4','vocabulary_match',4,'practice','easy',false,'{"question":"Nối từ trong bài với nghĩa:","pairs":[{"left":"retrieve","right":"tìm lại"},{"left":"whereabouts","right":"tung tích"},{"left":"surveillance","right":"sự giám sát"},{"left":"tamper with","right":"can thiệp, giả mạo"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u07-l4-p5','b2-u07-l4','multiple_choice',5,'practice','medium',false,'{"question":"Bằng chứng nào cho thấy tên trộm có thể ra cửa sau?","options":[{"id":"a","text":"Dấu giày"},{"id":"b","text":"Vết sơn ở lối thoát hiểm"},{"id":"c","text":"Camera ghi lại"}],"correctOptionId":"b","explanationVi":"''traces of paint on a fire exit.''"}'::jsonb),
 ('b2-u07-l4-p6','b2-u07-l4','multiple_choice',6,'practice','medium',false,'{"question":"Cảnh sát tin gì về số lượng kẻ trộm?","options":[{"id":"a","text":"Chắc chắn chỉ một người"},{"id":"b","text":"Không thể chỉ một người"},{"id":"c","text":"Không có kết luận"}],"correctOptionId":"b","explanationVi":"''can''t have been carried out by one person alone.''"}'::jsonb),
 ('b2-u07-l4-p7','b2-u07-l4','grammar_fill_blank',7,'practice','medium',false,'{"question":"Hoàn thành câu phê bình trong bài: ''He ought to ___ (stay) at his post.''","acceptedAnswers":["have stayed"],"explanationVi":"ought to have stayed = lẽ ra phải ở lại."}'::jsonb),
 ('b2-u07-l4-q1','b2-u07-l4','multiple_choice',8,'quiz','easy',true,'{"question":"Modal nào được dùng để suy luận CHẮC CHẮN trong bài?","options":[{"id":"a","text":"might have"},{"id":"b","text":"must have"},{"id":"c","text":"could have"}],"correctOptionId":"b","explanationVi":"must have = gần như chắc chắn đã xảy ra."}'::jsonb),
 ('b2-u07-l4-q2','b2-u07-l4','multiple_choice',9,'quiz','easy',true,'{"question":"Tung tích bức tranh hiện tại như thế nào?","options":[{"id":"a","text":"Đã tìm thấy"},{"id":"b","text":"Vẫn chưa biết"},{"id":"c","text":"Đã thu hồi"}],"correctOptionId":"b","explanationVi":"''Anyone with information on the whereabouts...should contact the authorities.'' — chưa tìm thấy."}'::jsonb),
 ('b2-u07-l4-q3','b2-u07-l4','multiple_choice',10,'quiz','medium',true,'{"question":"Cấu trúc trong ''should have checked the cameras'' diễn đạt điều gì?","options":[{"id":"a","text":"Suy luận chắc chắn"},{"id":"b","text":"Phê bình việc không làm đúng"},{"id":"c","text":"Khả năng yếu"}],"correctOptionId":"b","explanationVi":"should have = phê bình người không thực hiện trách nhiệm."}'::jsonb),
 ('b2-u07-l4-q4','b2-u07-l4','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Hoàn thành: ''The thief ___ (know) the security code — that''s why no alarm went off.''","acceptedAnswers":["must have known"],"explanationVi":"Gần chắc đã biết: must have known."}'::jsonb),
 ('b2-u07-l4-q5','b2-u07-l4','multiple_choice',12,'quiz','medium',true,'{"question":"Từ ''tamper with'' trong bài có nghĩa là?","options":[{"id":"a","text":"Sửa chữa đúng cách"},{"id":"b","text":"Can thiệp/giả mạo trái phép"},{"id":"c","text":"Lắp đặt mới"}],"correctOptionId":"b","explanationVi":"tamper with = can thiệp trái phép để phá hoại/gian lận."}'::jsonb),
 ('b2-u07-l4-q6','b2-u07-l4','vocabulary_match',13,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"surveillance","right":"sự giám sát"},{"left":"whereabouts","right":"tung tích"},{"left":"retrieve","right":"tìm lại"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u07-l4-q7','b2-u07-l4','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Hoàn thành: ''The theft ___ (carry out) by one person — it was too complex.''","acceptedAnswers":["can''t have been carried out","couldn''t have been carried out"],"explanationVi":"can''t have been carried out = không thể chỉ một người."}'::jsonb);
