 ('b2-u07-l5-q3','b2-u07-l5','multiple_choice',3,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG (phê bình đã làm điều không nên):","options":[{"id":"a","text":"You should have done that."},{"id":"b","text":"You shouldn''t have done that."},{"id":"c","text":"You needn''t have done that."}],"correctOptionId":"b","explanationVi":"Phê bình đã làm sai: shouldn''t have done."}'::jsonb),
