 ('b2-u07-l5-q5','b2-u07-l5','multiple_choice',5,'quiz','medium',true,'{"question":"Phân biệt: câu nào có nghĩa là ''đã làm nhưng không cần thiết''?","options":[{"id":"a","text":"I didn''t need to hurry."},{"id":"b","text":"I needn''t have hurried."},{"id":"c","text":"I should have hurried."}],"correctOptionId":"b","explanationVi":"needn''t have hurried = đã vội nhưng không cần."}'::jsonb),
