-- ══════════════════════════════════════════════════════════════════════════
-- UNIT 06 — Getting Things Done
-- Causative have/get; Reported Orders & Requests
-- ══════════════════════════════════════════════════════════════════════════

  '{"warmup":"''Tôi đã sửa xe.'' vs ''Tôi đã nhờ người sửa xe cho tôi.'' — Hai câu này khác nhau không? Tiếng Anh phân biệt bằng cách nào?",
    "objectives":["Dùng have/get + object + past participle để diễn đạt nhờ làm","Phân biệt have something done (nhờ làm) và do something yourself","Dùng get/have causative trong các ngữ cảnh khác nhau"],
    "grammarHtml":"<b>Causative Have:</b> have + object + V3 (past participle)<br><i>I had my hair cut. (Tôi đã cắt tóc — nhờ thợ cắt)</i><br><i>She has her car serviced every year.</i><br><b>Causative Get:</b> get + object + V3 (thông thường hơn have)<br><i>I got my laptop fixed. (Tôi nhờ ai đó sửa máy tính)</i><br><b>Sắc thái:</b><br>have = trang trọng hơn, nhấn kết quả dịch vụ<br>get = thông thường hơn, đôi khi nhấn nỗ lực đạt được<br><b>Các thì:</b><br>Present: I''m having the house painted. (đang thuê sơn)<br>Past: She had the contract checked.<br>Future: I''m going to have my teeth checked.<br><b>Lưu ý:</b> have + person + base verb = sai ngữ cảnh này; đúng là have + thing + V3<br><b>Causative get someone TO DO:</b><br>I got my brother to fix it. (thuyết phục/nhờ vả ai đó làm gì)",
    "vocabBlock":[
      {"word":"have something done","ipa":"/hæv ˈsʌmθɪŋ dʌn/","meaningVi":"nhờ ai làm gì (bị động nhân quả)","example":"I had my passport renewed last week."},
      {"word":"get something done","ipa":"/ɡet ˈsʌmθɪŋ dʌn/","meaningVi":"nhờ làm (thông thường)","example":"She got her nails done before the party."},
      {"word":"renovate","ipa":"/ˈrenəveɪt/","meaningVi":"cải tạo, tu sửa","example":"They renovated the old building."},
      {"word":"tailor-made","ipa":"/ˌteɪlə ˈmeɪd/","meaningVi":"may riêng, đặt làm","example":"He had a suit tailor-made."},
      {"word":"install","ipa":"/ɪnˈstɔːl/","meaningVi":"lắp đặt","example":"We had solar panels installed."}],
    "examples":[
      {"en":"I need to have my car repaired — the brakes are failing.","vi":"Tôi cần nhờ sửa xe — phanh đang hỏng."},
      {"en":"She got her wedding dress specially designed.","vi":"Cô ấy đặt thiết kế riêng cho váy cưới."},
      {"en":"They''re having their house renovated at the moment.","vi":"Họ đang nhờ người cải tạo nhà."},
      {"en":"I got my brother to help me move the furniture.","vi":"Tôi nhờ anh trai giúp chuyển đồ đạc."}],
    "commonMistakes":["❌ I had cut my hair. (tôi tự cắt) ≠ I had my hair cut. (nhờ thợ)","❌ I had my car to repair → ✅ I had my car repaired","get someone to do (infinitive) ≠ get something done (V3)"],
    "tips":["have/get + THING + V3 = nhờ làm dịch vụ.","get + PERSON + to do = thuyết phục/nhờ người cụ thể.","Progressive: be having/getting something done = đang trong quá trình thuê làm."]}'::jsonb);


  '{"warmup":"Sếp bạn nói: ''Nộp báo cáo trước thứ Sáu!'' — Bạn kể lại điều đó như thế nào? ''Sếp nói rằng...'' hay ''Sếp bảo tôi...''?",
    "objectives":["Dùng tell/ask/order/warn/advise/remind + object + to-infinitive để tường thuật lệnh, yêu cầu","Chuyển đổi câu mệnh lệnh trực tiếp → gián tiếp","Dùng đúng phủ định not to do"],
    "grammarHtml":"<b>Reported Orders & Requests:</b><br>Trực tiếp → Gián tiếp (câu mệnh lệnh)<br>''Submit the report!'' → He told me to submit the report.<br>''Don''t be late!'' → She told me not to be late.<br><b>Các động từ thường dùng:</b><br>tell + object + to do (lệnh, thông thường)<br>ask + object + to do (yêu cầu lịch sự)<br>order + object + to do (lệnh mạnh, chính thức)<br>warn + object + not to do (cảnh báo)<br>advise + object + to do (khuyên)<br>remind + object + to do (nhắc nhở)<br>forbid + object + to do (cấm)<br>encourage + object + to do (khuyến khích)<br><b>Lưu ý:</b> không dùng that-clause sau tell (mệnh lệnh):<br>❌ He told me that submit the report. → ✅ He told me to submit.",
    "vocabBlock":[
      {"word":"order","ipa":"/ˈɔːdə/","meaningVi":"ra lệnh (động từ)","example":"The commander ordered them to retreat."},
      {"word":"warn","ipa":"/wɔːn/","meaningVi":"cảnh báo","example":"She warned me not to touch it."},
      {"word":"forbid","ipa":"/fəˈbɪd/","meaningVi":"cấm","example":"He was forbidden to leave."},
      {"word":"remind","ipa":"/rɪˈmaɪnd/","meaningVi":"nhắc nhở","example":"Can you remind him to call?"},
      {"word":"encourage","ipa":"/ɪnˈkʌrɪdʒ/","meaningVi":"khuyến khích","example":"She encouraged me to apply."}],
    "examples":[
      {"en":"''Leave the office!'' → He ordered them to leave the office.","vi":"''Rời văn phòng!'' → Anh ấy ra lệnh cho họ rời văn phòng."},
      {"en":"''Please don''t touch the exhibits.'' → The guide asked us not to touch the exhibits.","vi":"''Vui lòng không chạm vào hiện vật.'' → Hướng dẫn viên đề nghị chúng tôi không chạm vào."},
      {"en":"''You should see a doctor.'' → She advised him to see a doctor.","vi":"''Bạn nên gặp bác sĩ.'' → Cô ấy khuyên anh ấy đi khám."},
      {"en":"''Remember to lock the door.'' → She reminded me to lock the door.","vi":"''Nhớ khoá cửa nhé.'' → Cô ấy nhắc tôi khoá cửa."}],
    "commonMistakes":["❌ She told to go → ✅ She told me to go (tell cần object)","❌ He said me to leave → ✅ He told me to leave (say không dùng với object + to)","❌ She warned me don''t touch → ✅ She warned me not to touch"],
    "tips":["Phủ định: tell/ask + object + NOT to do.","say ≠ tell: say không có object; tell cần object.","order/forbid = trang trọng, mạnh hơn tell/ask."]}'::jsonb);


  '{"warmup":"Bạn thường nhờ ai làm gì? Sửa xe? Cắt tóc? Thiết kế? Bạn biết những từ nào liên quan đến dịch vụ?",
    "objectives":["Học 10 từ vựng B2 về dịch vụ và cuộc sống","Dùng từ trong ngữ cảnh causative","Phân biệt từ theo ngữ cảnh dịch vụ chuyên nghiệp và đời thường"],
    "vocabBlock":[
      {"word":"premises","ipa":"/ˈpremɪsɪz/","meaningVi":"cơ sở, địa điểm (kinh doanh)","example":"The restaurant has just had its premises renovated."},
      {"word":"contractor","ipa":"/ˈkɒntræktə/","meaningVi":"nhà thầu","example":"We hired a contractor to fix the roof."},
      {"word":"maintenance","ipa":"/ˈmeɪntənəns/","meaningVi":"bảo trì, bảo dưỡng","example":"Regular maintenance prevents breakdowns."},
      {"word":"plumber","ipa":"/ˈplʌmə/","meaningVi":"thợ sửa ống nước","example":"We had a plumber fix the leaking pipe."},
      {"word":"electrician","ipa":"/ɪˌlekˈtrɪʃn/","meaningVi":"thợ điện","example":"Get an electrician to check the wiring."},
      {"word":"refurbish","ipa":"/ˌriːˈfɜːbɪʃ/","meaningVi":"tân trang lại","example":"The office was completely refurbished."},
      {"word":"upkeep","ipa":"/ˈʌpkiːp/","meaningVi":"chi phí bảo dưỡng","example":"The upkeep of the building is expensive."},
      {"word":"alter","ipa":"/ˈɔːltə/","meaningVi":"chỉnh sửa (quần áo/thiết kế)","example":"I had my suit altered to fit better."},
      {"word":"dry-clean","ipa":"/ˈdraɪ kliːn/","meaningVi":"giặt khô","example":"I have my coat dry-cleaned once a year."},
      {"word":"on-site","ipa":"/ˈɒn saɪt/","meaningVi":"tại chỗ","example":"We can do on-site repairs."}],
    "examples":[
      {"en":"We''re having the office premises refurbished next month.","vi":"Chúng tôi sẽ nhờ tân trang lại cơ sở văn phòng tháng tới."},
      {"en":"She had her dress altered to fit her perfectly.","vi":"Cô ấy nhờ chỉnh lại váy cho vừa hơn."},
      {"en":"We need to get the electrical wiring checked by a qualified electrician.","vi":"Chúng tôi cần nhờ thợ điện có trình độ kiểm tra hệ thống điện."}],
    "commonMistakes":["premises (số nhiều, nhưng chỉ một địa điểm): the premises are → đúng, dù chỉ 1 toà nhà.","maintenance (uncountable): regular maintenance (không có ''a maintenance'').","contractor (nhà thầu lớn) ≠ tradesperson (thợ như plumber, electrician)."],
    "tips":["have/get something done + từ vựng dịch vụ = ngữ cảnh tự nhiên.","on-site = tại chỗ (trái với remote)."]}'::jsonb);


  '{"warmup":"Đọc bài viết về dự án cải tạo nhà — chú ý cách dùng causative have/get và reported orders.",
    "objectives":["Đọc hiểu văn bản B2 về dịch vụ","Nhận biết causative have/get và reported speech trong ngữ cảnh","Trả lời câu hỏi suy luận"],
    "vocabBlock":[
      {"word":"quote","ipa":"/kwəʊt/","meaningVi":"báo giá","example":"Get several quotes before choosing a contractor."},
      {"word":"overrun","ipa":"/ˌəʊvəˈrʌn/","meaningVi":"vượt mức (chi phí/thời gian)","example":"The project overran by three weeks."},
      {"word":"disruption","ipa":"/dɪsˈrʌpʃn/","meaningVi":"sự gián đoạn","example":"The renovation caused a lot of disruption."},
      {"word":"deadline","ipa":"/ˈdedlaɪn/","meaningVi":"hạn chót","example":"They missed the deadline by two weeks."}],
    "examples":[
      {"en":"When Minh and Lan decided to have their apartment renovated, they expected it to take six weeks. They had the walls replastered, the floors retiled, and the kitchen completely refitted. They got a local contractor to provide a quote and were pleased with the price. However, the project overran significantly. ''Don''t worry,'' the contractor had told them, ''we''ll be done by Friday.'' But Friday came and went, and the electrician still hadn''t been called. Minh reminded the contractor to arrange the electrical work. Lan advised him to get everything in writing next time. ''We should have had the contract checked by a lawyer,'' she said. Despite the disruption, the finished apartment was exactly what they had imagined. They''re now having new furniture delivered and are having the place professionally cleaned before moving back in.","vi":"Khi Minh và Lan quyết định nhờ cải tạo căn hộ, họ kỳ vọng sẽ mất sáu tuần. Họ nhờ trát lại tường, lát lại sàn và tân trang hoàn toàn nhà bếp. Họ nhờ một nhà thầu địa phương báo giá và hài lòng với giá cả. Tuy nhiên, dự án bị chậm đáng kể. ''Đừng lo,'' nhà thầu đã nói với họ, ''chúng tôi sẽ xong trước thứ Sáu.'' Nhưng thứ Sáu đến rồi đi, và thợ điện vẫn chưa được gọi đến. Minh nhắc nhở nhà thầu thu xếp công việc điện. Lan khuyên anh ấy lần sau hãy lấy mọi thứ bằng văn bản. ''Lẽ ra chúng ta nên nhờ luật sư kiểm tra hợp đồng,'' cô nói. Dù có sự gián đoạn, căn hộ hoàn thiện đúng như những gì họ đã hình dung. Bây giờ họ đang nhờ giao nội thất mới và đang nhờ dọn dẹp chuyên nghiệp trước khi dọn vào ở lại."}],
    "commonMistakes":["Chú ý causative trong bài: had the walls replastered, got a contractor to provide, are having furniture delivered."],
    "tips":["Bài dùng nhiều thì khác nhau của causative (past, future, progressive).","We should have had... = tiếc nuối quá khứ với causative."]}'::jsonb);


  '{"warmup":"Ôn tập Unit 6: causative have/get, reported orders và từ vựng dịch vụ.","objectives":["Tổng hợp can-do Unit 6","Đạt ≥ 75% để hoàn thành Unit"],"vocabBlock":[],"examples":[],"commonMistakes":[],"tips":["Cần đúng ≥ 8/10 để qua Unit."]}'::jsonb);


UPDATE learning_units SET review_lesson_id = 'b2-u06-l5' WHERE id = 'b2-u06';

-- ══════════════════════════════════════════════════════════════════════════
-- UNIT 07 — Detective Work
-- Past Deduction Modals; Criticism/Regret (should/ought to have)
-- ══════════════════════════════════════════════════════════════════════════

  '{"warmup":"Bạn về nhà thấy cửa mở. Bạn nghĩ: ''Ai đó đã vào!'' hay ''Chắc là tôi quên khoá.'' — Bạn diễn đạt điều này trong tiếng Anh như thế nào?",
    "objectives":["Dùng must have/can''t have/could have/might have + V3 để suy luận về quá khứ","Phân biệt mức độ chắc chắn (almost certain → possible → impossible)","Nhận biết bằng chứng dẫn đến suy luận"],
    "grammarHtml":"<b>Suy luận về quá khứ:</b><br><b>must have + V3</b> = gần như chắc chắn ĐÃ xảy ra (positive deduction)<br><i>She must have left early — her car is gone.</i><br><b>can''t have + V3</b> = gần như chắc chắn KHÔNG xảy ra (negative deduction)<br><i>He can''t have eaten it — he''s allergic.</i><br><b>could have + V3</b> = có thể ĐÃ xảy ra (open possibility)<br><i>She could have taken the wrong bus.</i><br><b>might have + V3</b> = có lẽ ĐÃ xảy ra (weak possibility)<br><i>He might have forgotten about the meeting.</i><br><b>may have + V3</b> = tương tự might have, hơi trang trọng hơn<br><b>Scale độ chắc chắn:</b><br>must have (90-99%) > could have > might have (30-50%) > can''t have (1-10%)",
    "vocabBlock":[
      {"word":"deduce","ipa":"/dɪˈdjuːs/","meaningVi":"suy luận, suy diễn","example":"From the evidence, we can deduce what happened."},
      {"word":"clue","ipa":"/kluː/","meaningVi":"manh mối","example":"The detective found an important clue."},
      {"word":"suspect","ipa":"/ˈsʌspekt/","meaningVi":"nghi phạm","example":"The suspect could have fled the scene."},
      {"word":"evidence","ipa":"/ˈevɪdəns/","meaningVi":"bằng chứng","example":"The evidence suggests he was there."},
      {"word":"alibi","ipa":"/ˈælɪbaɪ/","meaningVi":"bằng chứng ngoại phạm","example":"She had a solid alibi."}],
    "examples":[
      {"en":"The lights are on — she must have come home already.","vi":"Đèn sáng — chắc cô ấy đã về nhà rồi."},
      {"en":"He can''t have stolen it — he was on holiday.","vi":"Anh ấy không thể đã lấy nó — anh ấy đang đi nghỉ."},
      {"en":"The door was unlocked — someone might have broken in.","vi":"Cửa không khoá — có lẽ ai đó đã đột nhập."},
      {"en":"She could have taken a different route to avoid the traffic.","vi":"Cô ấy có thể đã đi đường khác để tránh tắc đường."}],
    "commonMistakes":["❌ She must left early → ✅ She must have left (cần have + V3)","❌ He can''t has eaten → ✅ He can''t have eaten (sau modal luôn dùng have)","Phân biệt must have (suy luận) ≠ had to (obligation ở quá khứ thực tế)."],
    "tips":["Bằng chứng hiện tại → suy luận nguyên nhân quá khứ: must have / can''t have.","Không chắc → might have / could have.","could have ≠ was able to: could have = khả năng; was able to = thực sự làm được."]}'::jsonb);


  '{"warmup":"''Lẽ ra anh ấy không nên nói điều đó.'' / ''Lẽ ra tôi đã phải đến sớm hơn.'' — Bạn nói những câu này như thế nào?",
    "objectives":["Dùng should have / ought to have + V3 để phê bình hoặc tiếc nuối về quá khứ","Dùng needn''t have + V3 (làm nhưng không cần thiết)","Phân biệt với didn''t need to (không làm vì không cần)"],
    "grammarHtml":"<b>Phê bình & tiếc nuối về quá khứ:</b><br><b>should have + V3</b> = lẽ ra nên (nhưng không làm)<br><i>You should have called me. (Lẽ ra bạn gọi cho tôi — nhưng không gọi)</i><br><b>shouldn''t have + V3</b> = lẽ ra không nên (nhưng đã làm)<br><i>He shouldn''t have said that. (Lẽ ra anh ấy không nói điều đó)</i><br><b>ought to have + V3</b> = tương tự should have, hơi trang trọng<br><i>She ought to have read the instructions first.</i><br><b>needn''t have + V3</b> = đã làm nhưng thực ra không cần thiết<br><i>You needn''t have brought food — there''s plenty. (Bạn đã mang thức ăn nhưng không cần)</i><br><b>didn''t need to + V</b> = không làm vì biết không cần<br><i>I didn''t need to pay — it was free. (Không trả tiền, vì biết miễn phí)</i>",
    "vocabBlock":[
      {"word":"in hindsight","ipa":"/ɪn ˈhaɪndsaɪt/","meaningVi":"nhìn lại","example":"In hindsight, I should have prepared more."},
      {"word":"oversight","ipa":"/ˈəʊvəsaɪt/","meaningVi":"sự bỏ sót, thiếu sót","example":"That was a serious oversight on my part."},
      {"word":"negligent","ipa":"/ˈneɡlɪdʒənt/","meaningVi":"cẩu thả, bất cẩn","example":"The driver was negligent."},
      {"word":"precaution","ipa":"/prɪˈkɔːʃn/","meaningVi":"biện pháp phòng ngừa","example":"We should have taken more precautions."}],
    "examples":[
      {"en":"You should have told me earlier — I could have helped.","vi":"Lẽ ra bạn nói với tôi sớm hơn — tôi có thể đã giúp."},
      {"en":"She shouldn''t have left the meeting without permission.","vi":"Lẽ ra cô ấy không nên rời cuộc họp mà không xin phép."},
      {"en":"You needn''t have cooked so much food — we already had dinner.","vi":"Bạn đã nấu nhiều thức ăn nhưng không cần thiết — chúng tôi đã ăn tối rồi."},
      {"en":"In hindsight, we ought to have checked the weather forecast.","vi":"Nhìn lại, lẽ ra chúng tôi nên xem dự báo thời tiết."}],
    "commonMistakes":["❌ You should have tell me → ✅ should have told (V3)","needn''t have done ≠ didn''t need to do: needn''t have = đã làm (lãng phí); didn''t need to = không làm.","ought to have = should have (không phải ought have)."],
    "tips":["should have + V3 = phê bình hay tiếc nuối (ai đó không làm đúng).","shouldn''t have + V3 = phê bình (ai đó làm điều không nên).","needn''t have + V3 = làm rồi nhưng không cần."]}'::jsonb);


  '{"warmup":"Bạn có xem phim hình sự không? Bạn biết những từ nào về điều tra tội phạm?",
    "objectives":["Học 10 từ vựng B2 về tội phạm và điều tra","Dùng từ trong ngữ cảnh suy luận quá khứ","Phân biệt từ theo vai trò trong vụ án"],
    "vocabBlock":[
      {"word":"detective","ipa":"/dɪˈtektɪv/","meaningVi":"thám tử, điều tra viên","example":"The detective examined the crime scene."},
      {"word":"forensic","ipa":"/fəˈrensɪk/","meaningVi":"pháp y, điều tra khoa học","example":"Forensic evidence was crucial."},
      {"word":"motive","ipa":"/ˈməʊtɪv/","meaningVi":"động cơ (tội phạm)","example":"The detective established a motive."},
      {"word":"testimony","ipa":"/ˈtestɪməni/","meaningVi":"lời khai, chứng từ","example":"Her testimony was reliable."},
      {"word":"charge","ipa":"/tʃɑːdʒ/","meaningVi":"buộc tội, cáo buộc","example":"He was charged with fraud."},
      {"word":"acquit","ipa":"/əˈkwɪt/","meaningVi":"tuyên bố trắng án","example":"The jury acquitted her."},
      {"word":"convict","ipa":"/kənˈvɪkt/","meaningVi":"kết tội","example":"He was convicted of theft."},
      {"word":"witness","ipa":"/ˈwɪtnəs/","meaningVi":"nhân chứng","example":"A witness saw the incident."},
      {"word":"scene of the crime","ipa":"/siːn əv ðə kraɪm/","meaningVi":"hiện trường vụ án","example":"Police sealed the scene of the crime."},
      {"word":"frame","ipa":"/freɪm/","meaningVi":"vu oan, dàn dựng","example":"She claimed she had been framed."}],
    "examples":[
      {"en":"The detective must have found crucial evidence at the scene of the crime.","vi":"Thám tử chắc hẳn đã tìm thấy bằng chứng quan trọng tại hiện trường."},
      {"en":"The suspect can''t have been there — three witnesses confirmed his alibi.","vi":"Nghi phạm không thể đã có mặt ở đó — ba nhân chứng xác nhận bằng chứng ngoại phạm."},
      {"en":"She was convicted based on forensic evidence and witness testimony.","vi":"Cô bị kết tội dựa trên bằng chứng pháp y và lời khai của nhân chứng."}],
    "commonMistakes":["charge (buộc tội) ≠ convict (kết tội): charged = cáo buộc (chưa kết tội); convicted = đã kết tội.","acquit ≠ release: acquit = tuyên vô tội; release = thả (sau thụ án hoặc tạm giam).","frame (vu oan) = dàn dựng bằng chứng giả."],
    "tips":["scene of the crime / crime scene — cả hai đều đúng.","forensic + evidence/analysis/science.","charge → charged with + tội danh."]}'::jsonb);


  '{"warmup":"Một bức tranh nổi tiếng bị mất tại bảo tàng. Đọc báo cáo và thử suy luận chuyện gì đã xảy ra.",
    "objectives":["Đọc hiểu văn bản B2 kiểu điều tra","Nhận biết past deduction modals và should have trong ngữ cảnh","Suy luận từ bằng chứng được đưa ra"],
    "vocabBlock":[
      {"word":"retrieve","ipa":"/rɪˈtriːv/","meaningVi":"tìm lại, thu hồi","example":"Police hoped to retrieve the stolen painting."},
      {"word":"whereabouts","ipa":"/ˈweərəbaʊts/","meaningVi":"tung tích, nơi ở","example":"His whereabouts were unknown."},
      {"word":"surveillance","ipa":"/səˈveɪləns/","meaningVi":"sự giám sát","example":"The building had surveillance cameras."},
      {"word":"tamper with","ipa":"/ˈtæmpə wɪð/","meaningVi":"can thiệp, giả mạo","example":"Someone had tampered with the alarm."}],
    "examples":[
      {"en":"The painting must have been removed between midnight and 6am, when the museum was closed. The alarm hadn''t gone off, so the thief must have known the security code — or someone might have tampered with the system. The guard on duty should have checked the cameras every hour, but witnesses say he was absent. ''He ought to have stayed at his post,'' said the director. A forensic team found traces of paint on a fire exit, suggesting the thief could have left through the back of the building. No suspect has been charged yet, but police believe the theft can''t have been carried out by one person alone. Anyone with information on the whereabouts of the painting should contact the authorities.","vi":"Bức tranh chắc hẳn đã bị lấy đi giữa nửa đêm và 6 giờ sáng, khi bảo tàng đóng cửa. Chuông báo động không reo, vậy nên tên trộm chắc đã biết mã bảo mật — hoặc có người đã giả mạo hệ thống. Bảo vệ trực ca lẽ ra phải kiểm tra camera mỗi giờ, nhưng nhân chứng nói anh ta vắng mặt. ''Lẽ ra anh ta phải ở vị trí của mình,'' giám đốc nói. Đội pháp y tìm thấy vết sơn ở một lối thoát hiểm, cho thấy tên trộm có thể đã rời qua phía sau tòa nhà. Chưa có nghi phạm nào bị buộc tội, nhưng cảnh sát tin rằng vụ trộm không thể chỉ do một người thực hiện. Ai có thông tin về tung tích của bức tranh nên liên hệ nhà chức trách."}],
    "commonMistakes":["Để ý: must have been removed (bị động + suy luận), must have known, should have checked, ought to have stayed, could have left."],
    "tips":["Tìm bằng chứng trong văn bản → tìm cấu trúc suy luận đi kèm.","should/ought to have = phê bình người không thực hiện đúng trách nhiệm."]}'::jsonb);


